fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    let mut answer = vec![0; n];

    // Precompute the longest common prefix between all pairs of words
    let mut lcp = vec![vec![0; n]; n];

    // Compute LCP for all pairs
    for i in 0..n {
        for j in 0..n {
            if i == j {
                continue;
            }
            let mut len = 0;
            while len < words[i].len() && len < words[j].len() && words[i][len] == words[j][len] {
                len += 1;
            }
            lcp[i][j] = len;
        }
    }

    // For each index i, compute the maximum LCP of adjacent pairs after removing i
    for i in 0..n {
        let mut max_lcp = 0;
        // Check the pair (i-1, i) if i > 0
        if i > 0 {
            max_lcp = std::cmp::max(max_lcp, lcp[i - 1][i]);
        }
        // Check the pair (i, i+1) if i < n - 1
        if i < n - 1 {
            max_lcp = std::cmp::max(max_lcp, lcp[i][i + 1]);
        }
        answer[i] = max_lcp as i64;
    }

    answer
}
