fn solve(words: Vec<String>) -> Vec<i64> {
    let n = words.len();
    let mut answer = vec![0; n];

    // Preprocess to find the longest common prefix between all pairs of words
    let mut lcp = vec![vec![0; n]; n];

    // Compute LCP for all pairs of words
    for i in 0..n {
        for j in 0..n {
            if i != j {
                let mut len = 0;
                while len < words[i].len() && len < words[j].len() && words[i][len] == words[j][len] {
                    len += 1;
                }
                lcp[i][j] = len;
            }
        }
    }

    // For each index i, compute the maximum LCP between adjacent elements after removing i
    for i in 0..n {
        let mut max_lcp = 0;
        for j in 0..n {
            if j == i {
                continue;
            }
            if j > i {
                // Check the pair (words[j-1], words[j])
                let lcp_val = lcp[j - 1][j];
                if lcp_val > max_lcp {
                    max_lcp = lcp_val;
                }
            } else {
                // Check the pair (words[j], words[j+1])
                let lcp_val = lcp[j][j + 1];
                if lcp_val > max_lcp {
                    max_lcp = lcp_val;
                }
            }
        }
        answer[i] = max_lcp as i64;
    }

    answer
}
